   136→// ============== VERIFY HABIT PHOTO ==============
   137→
   138→export const verifyHabitPhoto = onCall(
   139→  {
   140→    secrets: [openaiApiKey],
   141→    timeoutSeconds: 60,
   142→    memory: '256MiB',
   143→  },
   144→  async (request) => {
   145→    if (!request.auth) {
   146→      throw new HttpsError('unauthenticated', 'User must be authenticated');
   147→    }
   148→
   149→    const userId = request.auth.uid;
   150→    const {photoUrl, habitDescription, habitName} = request.data;
   151→
   152→    await checkRateLimit(userId, 'verification', 20);
   153→
   154→    if (!photoUrl || !habitDescription) {
   155→      throw new HttpsError(
   156→        'invalid-argument',
   157→        'Missing required fields: photoUrl and habitDescription'
   158→      );
   159→    }
   160→
   161→    try {
   162→      const openai = new OpenAI({apiKey: openaiApiKey.value()});
   163→
   164→      console.log(`[${userId}] Verifying photo for habit: ${habitName}`);
   165→
   166→      const response = await openai.chat.completions.create({
   167→        model: 'gpt-4o-mini',
   168→        max_tokens: 300,
   169→        messages: [
   170→          {
   171→            role: 'user',
   172→            content: [
   173→              {
   174→                type: 'image_url',
   175→                image_url: {
   176→                  url: photoUrl,
   177→                },
   178→              },
   179→              {
   180→                type: 'text',
   181→                text: `You are verifying a habit tracking photo. The user claims they did this habit: "${habitDescription}"
   182→
   183→Analyze the photo and determine:
   184→1. Does this photo show evidence of the habit being done? (YES or NO)
   185→2. Brief reason (1 sentence)
   186→
   187→Respond in this format:
   188→VERIFIED: YES/NO
   189→REASON: [your reason]
   190→
   191→Be reasonable - if the photo shows legitimate effort, verify it. Only reject if it's clearly fake or unrelated.`,
   192→              },
   193→            ],
   194→          },
   195→        ],
   196→      });
   197→
   198→      const responseText = response.choices[0]?.message?.content || '';
   199→
   200→      const verified = responseText.includes('VERIFIED: YES');
   201→      const reasonMatch = responseText.match(/REASON: (.+)/);
   202→      const reason = reasonMatch ? reasonMatch[1].trim() : responseText;
   203→
   204→      console.log(`[${userId}] Verification result:`, {verified, reason});
   205→
   206→      await admin.firestore().collection('verificationLogs').add({
   207→        userId,
   208→        habitName,
   209→        verified,
   210→        reason,
   211→        timestamp: admin.firestore.FieldValue.serverTimestamp(),
   212→      });
   213→
   214→      return {
   215→        verified,
   216→        reason,
   217→        fullResponse: responseText,
   218→      };
   219→    } catch (error) {
   220→      console.error(`[${userId}] Error verifying photo:`, error);
   221→      throw new HttpsError('internal', 'Failed to verify photo with AI');
   222→    }
   223→  }
   224→);
