   257→
   258→      const prompt = success
   259→        ? `You're a cheeky British MMA fighter. The user just completed their habit "${habitName}" and is on a ${streak} day streak. Give them a 1-sentence motivational roast - hype them up but keep it playful. Be like a coach who's impressed but won't let them get a big head. Keep it under 20 words.`
   260→        : `You're a cheeky British MMA fighter. The user failed their habit "${habitName}" and broke their ${streak} day streak. Give them a funny, brutal 1-sentence roast that motivates them to get back on track. Mock them like a friend would. Keep it under 20 words.`;
   261→
   262→      console.log(
   263→        `[${userId}] Generating roast for: ${habitName} (success: ${success})`
   264→      );
   265→
   266→      const response = await openai.chat.completions.create({
   267→        model: 'gpt-4o-mini',
   268→        max_tokens: 100,
   269→        temperature: 1.0,
   270→        messages: [
   271→          {
   272→            role: 'user',
   273→            content: prompt,
   274→          },
   275→        ],
   276→      });
   277→
   278→      const roast =
   279→        response.choices[0]?.message?.content?.trim() || 'Keep going, lad!';
   280→
   281→      console.log(`[${userId}] Generated roast:`, roast);
   282→
   283→      return {roast};
