   217→  },
   218→  segment: {
   219→    position: 'absolute',
   220→    top: 0,
   221→    bottom: 0,
   222→    width: 2,
   223→    backgroundColor: Colors.background,
   224→  },
   225→});
   226→
   227→// ============== DIALOGUE BOX COMPONENT ==============
   228→
   229→function DialogueBox({ message }: { message: string }) {
   230→  return (
   231→    <View style={dialogueStyles.container}>
   232→      <View style={dialogueStyles.nameplate}>
   233→        <Text style={dialogueStyles.nameplateText}>APEX LAD</Text>
   234→      </View>
   235→      
   236→      <View style={dialogueStyles.dialogueContent}>
   237→        <Text style={dialogueStyles.messageText}>{message}</Text>
   238→      </View>
   239→    </View>
   240→  );
   241→}
   242→
   243→const dialogueStyles = StyleSheet.create({
   244→  container: {
   245→    marginBottom: Spacing.xl,
   246→    ...Shadows.dialogue,
   247→  },
   248→  nameplate: {
