   509→              <Text style={styles.emptyText}>
   510→                Create your first habit to get started with The Apex Lad.
   511→              </Text>
   512→            </View>
   513→          ) : (
   514→            habits.map((habit) => (
   515→              <SwipeableHabitCard
   516→                key={habit.id}
