// app/(tabs)/_layout.tsx
// Tactical Tab Navigation - Consistent button styling
import { Ionicons } from '@expo/vector-icons';
import { Tabs } from 'expo-router';
import React from 'react';
import { Platform, StyleSheet, View } from 'react-native';
import { Colors, Spacing } from '../../constants/theme';

export default function TabLayout() {
  return (
    <Tabs
      screenOptions={{
        headerShown: false,
        tabBarStyle: styles.tabBar,
        tabBarActiveTintColor: Colors.gold,
        tabBarInactiveTintColor: Colors.textMuted,
        tabBarShowLabel: true,
        tabBarLabelStyle: styles.tabLabel,
      }}
    >
      <Tabs.Screen
        name="index"
        options={{
          title: 'Home',
          tabBarIcon: ({ color, focused }) => (
            <View style={[styles.iconContainer, focused && styles.iconContainerActive]}>
              <Ionicons
                name={focused ? 'grid' : 'grid-outline'}
                size={22}
                color={color}
              />
            </View>
          ),
        }}
      />
      <Tabs.Screen
        name="add"
        options={{
          title: 'Create',
          tabBarIcon: ({ color, focused }) => (
            <View style={[styles.iconContainer, focused && styles.iconContainerActive]}>
              <Ionicons
                name={focused ? 'add-circle' : 'add-circle-outline'}
                size={24}
                color={color}
              />
            </View>
          ),
        }}
      />
      <Tabs.Screen
        name="stats"
        options={{
          title: 'Stats',
          tabBarIcon: ({ color, focused }) => (
            <View style={[styles.iconContainer, focused && styles.iconContainerActive]}>
              <Ionicons
                name={focused ? 'bar-chart' : 'bar-chart-outline'}
                size={22}
                color={color}
              />
            </View>
          ),
        }}
      />
    </Tabs>
  );
}

const styles = StyleSheet.create({
  tabBar: {
    backgroundColor: Colors.surface,
    borderTopWidth: 1,
    borderTopColor: Colors.border,
    height: Platform.OS === 'ios' ? 88 : 64,
    paddingTop: Spacing.sm,
    paddingBottom: Platform.OS === 'ios' ? 28 : Spacing.sm,
  },
  tabLabel: {
    fontSize: 10,
    fontWeight: '600',
    letterSpacing: 0.5,
    marginTop: 2,
  },
  iconContainer: {
    width: 36,
    height: 36,
    borderRadius: 8,
    alignItems: 'center',
    justifyContent: 'center',
  },
  iconContainerActive: {
    backgroundColor: Colors.goldMuted,
  },
});

// components/ApexSuccessScreen.tsx
// Tactical Success/Victory Screen - Larger image container

import { Ionicons } from '@expo/vector-icons';
import React, { useEffect, useRef } from 'react';
import {
  Animated,
  Dimensions,
  Image,
  Modal,
  ScrollView,
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
} from 'react-native';
import { BorderRadius, Colors, Spacing } from '../constants/theme';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');

interface ApexSuccessScreenProps {
  visible: boolean;
  streak: number;
  habitName: string;
  roastMessage: string;
  onClose: () => void;
}

export default function ApexSuccessScreen({
  visible,
  streak,
  habitName,
  roastMessage,
  onClose,
}: ApexSuccessScreenProps) {
  const scaleAnim = useRef(new Animated.Value(0)).current;
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const streakAnim = useRef(new Animated.Value(0)).current;
  const pulseAnim = useRef(new Animated.Value(1)).current;

  useEffect(() => {
    if (visible) {
      scaleAnim.setValue(0);
      fadeAnim.setValue(0);
      streakAnim.setValue(0);

      Animated.sequence([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 200,
          useNativeDriver: true,
        }),
        Animated.spring(scaleAnim, {
          toValue: 1,
          friction: 6,
          tension: 100,
          useNativeDriver: true,
        }),
        Animated.spring(streakAnim, {
          toValue: 1,
          friction: 5,
          tension: 80,
          useNativeDriver: true,
        }),
      ]).start();

      // Pulse animation for glow effect
      Animated.loop(
        Animated.sequence([
          Animated.timing(pulseAnim, {
            toValue: 1.05,
            duration: 1000,
            useNativeDriver: true,
          }),
          Animated.timing(pulseAnim, {
            toValue: 1,
            duration: 1000,
            useNativeDriver: true,
          }),
        ])
      ).start();
    }
  }, [visible]);

  if (!visible) return null;

  return (
    <Modal
      visible={visible}
      transparent={true}
      animationType="none"
      onRequestClose={onClose}
    >
      <Animated.View style={[styles.container, { opacity: fadeAnim }]}>
        <ScrollView 
          contentContainerStyle={styles.scrollContent}
          showsVerticalScrollIndicator={false}
        >
          {/* Top Status Bar */}
          <View style={styles.statusBar}>
            <View style={styles.statusItem}>
              <View style={[styles.statusDot, styles.statusDotActive]} />
              <Text style={styles.statusText}>VERIFIED</Text>
            </View>
            <View style={styles.statusDivider} />
            <View style={styles.statusItem}>
              <Ionicons name="shield-checkmark" size={14} color={Colors.success} />
              <Text style={styles.statusText}>LOGGED</Text>
            </View>
          </View>

          <View style={styles.content}>
            {/* Mission Complete Header */}
            <View style={styles.header}>
              <Text style={styles.missionLabel}>MISSION</Text>
              <Text style={styles.completeLabel}>COMPLETE</Text>
            </View>

            {/* Streak Display */}
            <Animated.View
              style={[
                styles.streakContainer,
                {
                  transform: [
                    { scale: streakAnim },
                    { scale: pulseAnim },
                  ],
                },
              ]}
            >
              <View style={styles.streakRing}>
                <View style={styles.streakInner}>
                  <Text style={styles.streakNumber}>{streak}</Text>
                  <Text style={styles.streakUnit}>DAY</Text>
                </View>
              </View>
              <View style={styles.streakBadge}>
                <Ionicons name="flame" size={20} color={Colors.streak} />
              </View>
            </Animated.View>

            {/* Character Image - LARGER */}
            <Animated.View
              style={[
                styles.imageContainer,
                { transform: [{ scale: scaleAnim }] },
              ]}
            >
              <Image
                source={require('../assets/images/apex-pleased.png')}
                style={styles.characterImage}
                resizeMode="cover"
              />
            </Animated.View>

            {/* Message Card */}
            <View style={styles.messageCard}>
              <View style={styles.messageHeader}>
                <Text style={styles.habitName}>{habitName.toUpperCase()}</Text>
                <View style={styles.verifiedBadge}>
                  <Ionicons name="checkmark" size={12} color={Colors.background} />
                </View>
              </View>
              <View style={styles.messageDivider} />
              <Text style={styles.roastMessage}>"{roastMessage}"</Text>
              <Text style={styles.attribution}>— THE APEX LAD</Text>
            </View>

            {/* Continue Button */}
            <TouchableOpacity style={styles.continueButton} onPress={onClose}>
              <Text style={styles.continueText}>CONTINUE</Text>
              <Ionicons name="arrow-forward" size={18} color={Colors.background} />
            </TouchableOpacity>
          </View>
        </ScrollView>
      </Animated.View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: Colors.background,
  },
  scrollContent: {
    flexGrow: 1,
    paddingBottom: Spacing.xl,
  },
  statusBar: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
