     1→// components/NotificationSettings.tsx
     2→// Push notification toggle for settings screen
     3→
     4→import React, { useEffect, useState } from 'react';
     5→import {
     6→  View,
     7→  Text,
     8→  Switch,
     9→  StyleSheet,
    10→  Alert,
    11→  Linking,
    12→  ActivityIndicator,
    13→} from 'react-native';
    14→import { Ionicons } from '@expo/vector-icons';
    15→import { doc, getDoc } from 'firebase/firestore';
    16→import { Colors, BorderRadius, Spacing } from '../constants/theme';
    17→import { auth, db } from '../config/firebase';
    18→import {
    19→  enablePushNotifications,
    20→  disablePushNotifications,
    21→  areNotificationsEnabled,
    22→} from '../utils/pushNotifications';
    23→
    24→export default function NotificationSettings() {
    25→  const [enabled, setEnabled] = useState(false);
    26→  const [loading, setLoading] = useState(true);
    27→  const [toggling, setToggling] = useState(false);
    28→
    29→  useEffect(() => {
    30→    loadSettings();
    31→  }, []);
    32→
    33→  const loadSettings = async () => {
    34→    try {
    35→      const hasPermission = await areNotificationsEnabled();
    36→      
    37→      const userId = auth.currentUser?.uid;
    38→      if (userId) {
    39→        const userDoc = await getDoc(doc(db, 'users', userId));
    40→        const userData = userDoc.data();
    41→        const firestoreEnabled = userData?.notificationsEnabled ?? false;
    42→        
    43→        setEnabled(hasPermission && firestoreEnabled);
    44→      }
    45→    } catch (error) {
    46→      console.error('Error loading notification settings:', error);
    47→    } finally {
    48→      setLoading(false);
    49→    }
    50→  };
    51→
    52→  const handleToggle = async (value: boolean) => {
    53→    setToggling(true);
    54→    
    55→    try {
    56→      if (value) {
    57→        const success = await enablePushNotifications();
    58→        
    59→        if (success) {
    60→          setEnabled(true);
    61→        } else {
    62→          Alert.alert(
    63→            'Enable Notifications',
    64→            'To receive habit reminders, please enable notifications in your device settings.',
    65→            [
    66→              { text: 'Cancel', style: 'cancel' },
    67→              { text: 'Open Settings', onPress: () => Linking.openSettings() },
    68→            ]
    69→          );
    70→        }
    71→      } else {
    72→        await disablePushNotifications();
    73→        setEnabled(false);
    74→      }
    75→    } catch (error) {
    76→      console.error('Error toggling notifications:', error);
    77→      Alert.alert('Error', 'Failed to update notification settings.');
    78→    } finally {
    79→      setToggling(false);
    80→    }
    81→  };
    82→
    83→  if (loading) {
    84→    return (
    85→      <View style={styles.container}>
    86→        <View style={styles.sectionHeader}>
    87→          <Ionicons name="notifications-outline" size={18} color={Colors.textMuted} />
    88→          <Text style={styles.sectionTitle}>REMINDERS</Text>
    89→        </View>
    90→        <View style={[styles.row, styles.loadingRow]}>
    91→          <ActivityIndicator color={Colors.gold} />
    92→        </View>
    93→      </View>
    94→    );
    95→  }
    96→
    97→  return (
    98→    <View style={styles.container}>
    99→      <View style={styles.sectionHeader}>
   100→        <Ionicons name="notifications-outline" size={18} color={Colors.textMuted} />
   101→        <Text style={styles.sectionTitle}>REMINDERS</Text>
   102→      </View>
   103→
   104→      <View style={styles.row}>
   105→        <View style={styles.rowLeft}>
   106→          <Ionicons name="alarm-outline" size={22} color={Colors.textSecondary} />
   107→          <View style={styles.rowText}>
   108→            <Text style={styles.rowTitle}>Daily Reminders</Text>
   109→            <Text style={styles.rowSubtitle}>Get nudged if habits aren't done</Text>
   110→          </View>
   111→        </View>
   112→        {toggling ? (
   113→          <ActivityIndicator color={Colors.gold} />
   114→        ) : (
   115→          <Switch
   116→            value={enabled}
   117→            onValueChange={handleToggle}
   118→            trackColor={{ false: Colors.border, true: Colors.gold }}
   119→            thumbColor={Colors.textPrimary}
   120→            ios_backgroundColor={Colors.border}
   121→          />
   122→        )}
   123→      </View>
   124→
   125→      {enabled && (
   126→        <View style={styles.infoBox}>
   127→          <Ionicons name="information-circle-outline" size={16} color={Colors.textMuted} />
   128→          <Text style={styles.infoText}>
   129→            You'll get a reminder at 8 PM if you have incomplete habits, and a streak warning at 10 PM.
   130→          </Text>
   131→        </View>
   132→      )}
   133→    </View>
   134→  );
   135→}
   136→
   137→const styles = StyleSheet.create({
   138→  container: {
   139→    marginBottom: Spacing.xl,
   140→  },
   141→  sectionHeader: {
   142→    flexDirection: 'row',
   143→    alignItems: 'center',
   144→    paddingVertical: Spacing.md,
   145→    marginBottom: Spacing.sm,
   146→  },
   147→  sectionTitle: {
   148→    fontSize: 12,
   149→    fontWeight: '600',
   150→    color: Colors.textMuted,
   151→    letterSpacing: 2,
   152→    marginLeft: Spacing.sm,
   153→  },
   154→  row: {
   155→    flexDirection: 'row',
